angular.module('angular-flatpickr', []).directive('enableDatepicker', [function () {
    return {
        restrict: 'EA',
        require : 'ngModel',
        scope :{
            options : "=",
            ngChnage : "&?",           
        },
        link: function (scope, iElement, iAttrs, ngModel) {
            var obj = new flatpickr(iElement[0], scope.options);
            // var model = dpElem.children('input').attr("ng-model");
            scope.$watch("options", function(newVal){
                $.map(newVal, function(value, key){
                   obj.set(key, value);
                })
                //console.log(obj);
            },true)

           // console.log(obj)
            ngModel.$render = function(){
                // if value is undefined/null do not do anything, unless some date was set before
                if (!ngModel.$viewValue) {
                     obj.clear();
                } else if (ngModel.$viewValue) {
                    ngModel.$setViewValue(ngModel.$viewValue); 
                    obj.setDate(ngModel.$viewValue, false, scope.options.dateFormat);
                }
            }
            //Listen on destroy 
            iElement.on("$destroy",function(){
               obj.destroy();              
            });        
        }
    };
}]);